def _v23_form_anchors(core):
    """Ancoras forma=conteudo: strings EXATAS (mesmo format-spec dos emissores) que
    DEVEM aparecer nos artefatos recem-escritos, regeneradas do core VIVO. Se o
    emissor mudar um format-spec sem atualizar aqui, o modulo REPROVA (fail-closed
    textual: melhor um falso-vermelho que um forma!=conteudo silencioso)."""
    _inv = core.get("alpha_inversion", {})
    _ase = (core.get("area_scale_newton_equivalence") or {}).get("equivalence", {})
    md, pt = "um_grande_atrator_forma_canonica.md", "um_grande_atrator_pt.tex"
    return [
        ("omega_I_eq_1_md", md, "ω(I)=tr(I)/2 = %d" % int(round(core["omega_I"]))),
        ("half_nat_md", md, "x = 1/2  →  S_∂ = 1/2 nat"),
        ("sqrt_e_12f_md", md, "S_∂ = 1/2  →  Vol_∂^min = e^{1/2} = √e = %.12f" % core["SQRT_E"]),
        ("alpha_obs_12f_md", md, "α_obs = √(1−q²) = %.12f" % _inv.get("alpha_form", core["alpha"])),
        ("beta_15f_md", md, "β_TGL = √e·α_obs = √e·√(1−q²) = %.15f" % core["beta"]),
        ("theta_M_6f_md", md, "θ_M = arcsin√β = %.6f°" % core["theta_M_deg"]),
        ("s_can_12f_md", md, "s_can = 1/(4π) = %.12f" % core["s_can"]),
        ("eta_times_G_6g_md", md, "η·G = %.6g" % _ase.get("eta_times_G", 0.25)),
        ("sqrt_e_12f_tex_pt", pt, r"\sqrt{e}=" + ("%.12f" % core["SQRT_E"])),
        ("beta_12f_tex_pt", pt, r"\bTGL=\sqrt e\,\alpha_{\mathrm{obs}}=" + ("%.12f" % core["beta"])),
    ]


def finalize_interface_is_light(core):
    """v23 -- fecha o check forma=conteudo APOS a geracao dos artefatos: le a forma
    canonica (.md) e o artigo PT (.tex) recem-escritos e exige que os numeros-chave
    impressos coincidam EXATAMENTE (mesmo format-spec) com o conteudo vivo do core.
    Divergencia REPROVA o modulo. Muta core["interface_is_light"] (o chamador deve
    re-serializar o JSON antes do selo)."""
    iil = core.get("interface_is_light")
    if not isinstance(iil, dict):
        return None
    texts = {}
    for fn in ("um_grande_atrator_forma_canonica.md", "um_grande_atrator_pt.tex",
               "um_grande_atrator_en.tex", "um_grande_atrator_manifest.md"):
        try:
            texts[fn] = open(os.path.join(OUT, fn), "r", encoding="utf-8").read()
        except OSError:
            texts[fn] = ""
    checks, mismatches = [], []
    for name, fn, expected in _v23_form_anchors(core):
        ok = bool(expected in texts.get(fn, ""))
        checks.append((name, ok))
        if not ok:
            mismatches.append({"anchor": name, "file": fn, "expected": expected})
    form_ok = bool(checks and all(v for _, v in checks))
    iil["form_content"] = {
        "status": "VERIFIED" if form_ok else "MISMATCH",
        "checked_files": ["um_grande_atrator_forma_canonica.md", "um_grande_atrator_pt.tex"],
        "anchors_checked": len(checks),
        "anchors": [(n, bool(v)) for n, v in checks],
        "mismatches": mismatches,
        "reading": ("o que o codigo computa (core vivo) == o que ele inscreve (artefato impresso); "
                    "residuo textual zero por construcao do mesmo format-spec"),
    }
    # v23.1/v24 -- marcadores canonicos: UMA fonte de runtime relida em TODOS os
    # artefatos (md, tex PT/EN, manifesto, JSON), comparacao byte-a-byte por linha.
    expected_markers = list(core.get("tgl_canonical_markers", []))
    mk_files = {}
    for fn in ("um_grande_atrator_forma_canonica.md", "um_grande_atrator_pt.tex",
               "um_grande_atrator_en.tex", "um_grande_atrator_manifest.md"):
        missing = [ln for ln in expected_markers if ln not in texts.get(fn, "")]
        mk_files[fn] = {"present": len(expected_markers) - len(missing), "missing": missing}
    js_ok = False
    try:
        _art = json.load(open(os.path.join(OUT, "um_grande_atrator.json"), "r", encoding="utf-8"))
        js_ok = bool(list(_art.get("core", {}).get("tgl_canonical_markers", [])) == expected_markers)
    except Exception:
        js_ok = False
    mk_ok = bool(expected_markers and js_ok
                 and all(not v["missing"] for v in mk_files.values()))
    iil["canonical_markers"] = {
        "status": "VERIFIED" if mk_ok else "MISMATCH",
        "expected": expected_markers, "per_file": mk_files, "json_identical": js_ok,
        "flow": "computar -> renderizar -> reler -> comparar -> selar",
    }
    iil["checks"] = list(iil["checks"]) + [("form_equals_content_in_artifacts", form_ok),
                                           ("canonical_markers_identical_all_artifacts", mk_ok)]
    iil["all_verified"] = bool(all(v for _, v in iil["checks"]))
    iil["verdict"] = ("INTERFACE_IS_LIGHT_VERIFIED" if iil["all_verified"]
                      else ("FORM_CONTENT_IDENTITY_FAILED" if not (form_ok and mk_ok)
                            else "INTERFACE_IS_LIGHT_FALHOU"))
    return iil


def run_um(ONE):
    """ONE=1 -> toda a algebra -> massa do GA (dois modos) -> tudo verificado ao vivo."""
    I = ONE * np.eye(2); omega_I = float(np.trace(I) / 2.0)
    TWO = ONE + ONE; HALF = ONE / TWO; FOUR = TWO + TWO
    PI = 4.0 * np.arctan(ONE); SQRT_E = np.exp(HALF)
    # Meia-Nat derivada: x = 1 - x => x = 1/2
    x = HALF; mn_resid = abs((ONE - x) - x)
    S_boundary = HALF; w_max = HALF
    s_can = ONE / (FOUR * PI)
    # MOTOR CANONICO (forma de Lagrange): 1_abs -> q -> alpha=sqrt(1-q^2) -> beta=sqrt(e) alpha.
    # q = polarizacao termico-modular do zero modular (variavel fisica); kappa = multiplicador de Lagrange.
    # CODATA NAO move a cadeia: q=q_QED so' no modo de validacao externa. 1 = q^2 + alpha^2 (conservacao).
    _qed = validate_against_qed(0.0, SEALED_CODATA_ALPHA)
    q = _qed["q_QED"]                              # [QED-VALIDATION] a polarizacao realizada pela natureza
    laform = alpha_lagrange_form(q)               # motor canonico (1=q^2+alpha^2)
    alpha = laform["alpha_form"]                  # = sqrt(1-q^2) = alpha_obs [DER]
    beta = laform["beta_form"]                    # = sqrt(e) sqrt(1-q^2) [DER]
    theta_M = float(np.arcsin(np.sqrt(beta)))
    # --- PONTE FISICA: radical angular + impedancia modular (leitura; valor ainda do input) ---
    # q = radical angular da diferenca modular inscrito no angulo de fronteira: q=sqrt(1-sin^4(theta_M)/e)
    #   (= sqrt(1-alpha^2), pois alpha=sin^2(theta_M)/sqrt(e)=beta/sqrt(e)). NAO e' theta_M nem 1-theta_M.
    q_angular = float(np.sqrt(max(0.0, 1.0 - np.sin(theta_M) ** 4 / np.e)))
    # fronteira reciproca sem perdas: q=reflexao=(Zb-Zl)/(Zb+Zl), alpha=transmissao=2sqrt(ZbZl)/(Zb+Zl);
    #   kappa=log(Zb/Zl) (rapidez de impedancia); q^2+alpha^2=1 = conservacao de fluxo.
    Z_ratio = float(np.exp(_qed["kappa_QED"])) if _qed["kappa_QED"] < 700 else float("inf")  # Zbacia/Zluz
    qed = validate_against_qed(alpha, SEALED_CODATA_ALPHA)   # validacao final (residuo)
    R_partial = (1.0 / alpha) if alpha > 0 else float("inf")  # LEGADO: derivado APOS a forma, NAO motor
    alpha_inversion = {
        # --- forma de Lagrange (MOTOR CANONICO) ---
        "alpha_abs": laform["alpha_abs"], "q": q,
        "alpha_form": alpha, "beta_form": beta,
        # --- ponte fisica (radical angular + impedancia modular) ---
        "q_angular_radical": q_angular,           # = sqrt(1 - sin^4(theta_M)/e) = sqrt(1-alpha^2)
        "impedance_ratio_Zb_over_Zl": Z_ratio,    # Zbacia/Zluz = e^kappa ; alpha = transmissao luminosa
        "impedance_reading": ("q=reflexao=(Zb-Zl)/(Zb+Zl); alpha=transmissao=2sqrt(ZbZl)/(Zb+Zl); "
                              "q^2+alpha^2=1 = conservacao de fluxo na fronteira modular sem perdas. "
                              "alpha = transmissao luminosa atraves da impedancia modular do zero. "
                              "DERIVAR alpha autonomamente = derivar Zb/Zl (= q) SEM o valor QED (ABERTO)."),
        "identity": laform["identity"], "identity_residual": laform["identity_residual"],
        "em_verdict": laform["verdict"],          # "1=1=VERDADE" (= 1 = q^2 + alpha^2)
        "engine": laform["engine"],
        # --- validacao externa QED (so' aqui o CODATA entra) ---
        "alpha_CODATA_validation": SEALED_CODATA_ALPHA, "q_QED": qed["q_QED"],
        "kappa_QED": qed["kappa_QED"], "residual_alpha": qed["residual_alpha"],
        # --- legado (compatibilidade; NAO motor canonico) ---
        "R_partial": R_partial, "R_partial_source": "LEGADO_DERIVADO_DA_FORMA_NAO_MOTOR",
        "alpha_obs_pred": alpha, "inv_R_partial": (1.0 / R_partial) if R_partial != float("inf") else 0.0,
        "alpha_is_projection_of_absolute_one": True,
        "status": ("LEGADO_COMPATIBILIDADE_CODATA_NAO_MOTOR_CANONICO. Motor = forma de Lagrange: "
                   "1_abs=1 -> q (polarizacao termico-modular) -> alpha=sqrt(1-q^2) -> beta=sqrt(e)alpha; "
                   "1 = q^2 + alpha^2 (identidade conservada). R_partial=1/alpha derivado APOS a forma, "
                   "nunca de CODATA. CODATA so' valida: q_QED=sqrt(1-alpha_QED^2). O Um nao se perde no "
                   "zero modular; decompoe-se em resistencia termica q^2 e corrente luminosa alpha^2.")}
    clock_theorem = clock_theorem_reduction(ONE)   # face EM = fronteira aberta nomeada (verificada ao vivo)
    alpha_form_proof = prove_alpha_form(ONE)        # MODULO DE PROVA: Teorema do Colapso da Forma de alpha
    contour_theory = prove_contour_theory(ONE, qed["kappa_QED"])  # PROVA: 1=0_mod (anticomut. + GKLS + Meia-Nat)
