    s.append(r"\section{Derivação do raio nomeado: $R_{\mathrm{named}}=2\bTGL R_{\mathrm{struct}}$ (L4)}")
    s.append(r"\begin{deriv}[A borda auto-conjugada e a fidelidade de identidade]")
